// ── Universal syntax checkers — zero config, always run ──
const SYNTAX_CHECKERS = {
    ts:  (f: string) => `node --check "${f}"`,
    tsx: (f: string) => `node --check "${f}"`,
    js:  (f: string) => `node --check "${f}"`,
    mjs: (f: string) => `node --check "${f}"`,
    cjs: (f: string) => `node --check "${f}"`,
    py:  (f: string) => `python3 -c "import ast;ast.parse(open('${f}').read())"`,
    sh:  (f: string) => `bash -n "${f}"`,
    rs:  (f: string) => `rustc --edition 2021 "${f}" --crate-type lib -o /dev/null 2>&1 || true`,
};

function execAsync(cmd: string): Promise<{ stdout: string; stderr: string }> {
    return new Promise((resolve, reject) => {
        require("child_process").exec(cmd, { timeout: 10000 }, (err: any, stdout: string, stderr: string) => {
            if (err) reject({ ...err, stdout, stderr });
            else resolve({ stdout, stderr });
        });
    });
}
```

