pi.on("tool_result", async (event, ctx) => {
    const state = getState(ctx);
    if (!state.autoLint) return;
    if (event.toolName !== "edit" && event.toolName !== "write") return;

    // Track edited file path
    const rawPath = (event.input as Record<string, unknown>)?.path
        || (event.input as Record<string, unknown>)?.file_path;
    if (rawPath && typeof rawPath === "string") {
        state.lastEditedFiles.push(rawPath);
    }

    if (state.lastEditedFiles.length === 0) return;

    const files = [...state.lastEditedFiles];
    state.lastEditedFiles = [];

    // === TIER 1: Universal syntax check — ALWAYS runs, no config needed ===
    const syntaxErrors: string[] = [];
    for (const file of files) {
        const ext = file.split(".").pop()?.toLowerCase();
        const checker = SYNTAX_CHECKERS[ext as keyof typeof SYNTAX_CHECKERS];
        if (checker) {
            try {
                const { stdout, stderr } = await execAsync(checker(file));
                if (stderr) syntaxErrors.push(`  ${file}: ${stderr.trim()}`);
            } catch (e: any) {
                syntaxErrors.push(`  ${file}: ${e.stderr || e.message}`);
            }
        }
    }

    if (syntaxErrors.length > 0) {
        pi.sendMessage({
            customType: "lint-guard",
            content: `⚠ Syntax errors:\n${syntaxErrors.join("\n")}`,
            display: true,
            details: { linter: "syntax-check", files: files },
        }, { deliverAs: "steer" });
        return; // Don't run project linter if syntax is broken — fix syntax first
    }

    // === TIER 2: Project-level lint (uses config) ===
    const result = await runLinter(ctx.cwd, files);

    if (!result.success) {
        pi.sendMessage({
            customType: "lint-guard",
            content: `⚠ Lint failed [${result.linter}]:\n${result.errors}`,
            display: true,
            details: { linter: result.linter, files: result.filesChecked },
        }, { deliverAs: "steer" });
    } else if (result.linter === "none") {
        // Inform that no project linter was found (but syntax is clean)
        pi.sendMessage({
            customType: "lint-guard",
            content: `✓ Syntax OK (no project linter found for ${files.join(", ")})`,
            display: true,
            details: { linter: "none", files: files },
        }, { deliverAs: "steer" });
    } else {
        // Lint passed — inform
        pi.sendMessage({
            customType: "lint-guard",
            content: `✓ Lint passed [${result.linter}]: ${files.join(", ")}`,
            display: true,
            details: { linter: result.linter, files: result.filesChecked },
        }, { deliverAs: "steer" });
    }
});
```

