```typescript
export function summarizeGoal(goal: string): string {
    // Strip URLs and markdown code blocks first — not informative for plan goal
    let cleaned = goal.replace(/https?:\/\/[^\s]+/g, '');
    cleaned = cleaned.replace(/```[\s\S]*?```/g, '');
    cleaned = cleaned.replace(/`[^`]+`/g, '');
    cleaned = cleaned.trim();

    // Take first line or first 80 chars
    const firstLine = cleaned.split('\n')[0]?.trim() || cleaned;
    const maxLen = 80;
    if (firstLine.length <= maxLen) return firstLine;
    return firstLine.slice(0, maxLen - 3) + '...';
}
```

This way:
- URLs are stripped (don't pollute the goal)
- Code blocks are stripped
- First 80 chars of the first meaningful line
- Ends with "..." if truncated
- No truncation if under 80 chars

