/**
 * Conversation Viewer — Overlay to watch subagent conversations in real-time.
 * Inspired by pi-subagents' conversation-viewer.ts.
 */
import type { TUI, Container, Text, Key } from "@mariozechner/pi-tui";

interface ViewerOptions {
    session: any;        // AgentSession
    description: string; // Subagent description
    onStop: () => void;  // Callback to abort the subagent
    tui: TUI;
    theme: any;
}

export function openConversationViewer(opts: ViewerOptions): void {
    const { session, description, onStop, tui, theme } = opts;
    let scrollOffset = 0;
    let autoScroll = true;
    let stopArmed = false;
    let closed = false;

    // Subscribe to session events for live updates
    const unsubscribe = session.subscribe(() => {
        if (!closed) tui.requestRender();
    });

    const close = () => {
        closed = true;
        unsubscribe();
    };

    // Build the overlay content
    function renderContent(): string[] {
        // Get messages from session or from subscriber
        const messages: any[] = [];

        // Build lines from messages
        const lines: string[] = [];
        for (const msg of messages) {
            if (msg.role === "user") {
                // Show user message header
                lines.push("User:");
                if (typeof msg.content === "string") {
                    // Wrap long lines
                    const wrapped = msg.content.split("\n");
                    for (const line of wrapped) lines.push("  " + line);
                }
                lines.push("");
            } else if (msg.role === "assistant") {
                lines.push("Assistant:");
                // Start with thinking/reasoning as first line
                if (typeof msg.content === "string") {
                    const contentLines = msg.content.split("\n");
                    for (const line of contentLines.slice(0, 10)) {
                        if (line.trim()) lines.push("  " + line);
                    }
                    if (contentLines.length > 10) lines.push("  ... (" + (contentLines.length - 10) + " more lines)");
                }
                // Show tool calls
                if (msg.toolCalls && msg.toolCalls.length > 0) {
                    for (const tc of msg.toolCalls) {
                        if (tc.toolName === "read") {
                            const path = tc.input?.path || tc.input?.file_path || "";
                            lines.push("  [read: " + path + "]");
                        } else if (tc.toolName === "bash") {
                            const cmd = (tc.input?.command || "").slice(0, 80);
                            lines.push("  [bash: " + cmd + "]");
                        } else if (tc.toolName === "edit" || tc.toolName === "write") {
                            const path = tc.input?.path || "";
                            const count = tc.input?.edits?.length || 0;
                            lines.push("  [" + tc.toolName + ": " + path + (count ? " (" + count + " changes)" : "") + "]");
                        } else if (tc.toolName === "grep" || tc.toolName === "find") {
                            const pattern = tc.input?.pattern || "";
                            const path = tc.input?.path || "";
                            lines.push("  [" + tc.toolName + ": " + pattern + " in " + path + "]");
                        } else {
                            lines.push("  [" + tc.toolName + "]");
                        }
                    }
                }
                lines.push("");
            } else if (msg.role === "tool_result") {
                lines.push("Result:");
                const content = typeof msg.content === "string" ? msg.content : "";
                const preview = content.split("\n").slice(0, 3).join("\n");
                if (preview) {
                    for (const line of preview.split("\n")) lines.push("  " + line);
                }
                if (content.split("\n").length > 3) lines.push("  ... (truncated)");
                lines.push("");
            }
        }

        // If no messages yet, show "Waiting for subagent to start..."
        if (lines.length === 0) {
            lines.push("  Waiting for subagent to start...");
        }

        return lines;
    }

    // Register the overlay with TUI
    tui.setOverlay({
        key: "conversation-viewer",
        zIndex: 100,
        render: () => {
            const termW = tui.size.width;
            const termH = tui.size.height;
            const overlayW = Math.floor(termW * 0.9);
            const overlayH = Math.floor(termH * 0.7);
            const x = Math.floor((termW - overlayW) / 2);
            const y = Math.floor((termH - overlayH) / 2);

            const container = new Container(overlayW, overlayH, x, y);

            // Header
            const stopIndicator = stopArmed ? "  [x] ABORT? Press x again to confirm" : "";
            const headerText = subagentDisplay + stopIndicator;
            // Title bar
            container.box(x, y, overlayW, 3, theme);

            // Messages area with scrolling
            const contentLines = renderContent();
            // Apply scroll
            const visibleLines = contentLines.slice(scrollOffset, scrollOffset + overlayH - 5);
            // Render each visible line

            // Footer with controls
            // "↑↓ scroll · End auto-scroll · x to stop · Esc close"

            return container;
        },
        onKey: (key: any) => {
            if (key.name === "escape" || key.name === "q") {
                close();
                return true;
            }
            if (key.name === "x") {
                if (stopArmed) {
                    onStop();
                    close();
                } else {
                    stopArmed = true;
                    // Auto-disarm after 2s if not confirmed
                    setTimeout(() => { stopArmed = false; tui.requestRender(); }, 2000);
                }
                return true;
            }
            if (key.name === "up" || key.name === "k") {
                if (scrollOffset > 0) { scrollOffset--; autoScroll = false; }
                return true;
            }
            if (key.name === "down" || key.name === "j") {
                scrollOffset++; autoScroll = false;
                return true;
            }
            if (key.name === "end" || key.name === "G") {
                scrollOffset = 0; autoScroll = true;
                return true;
            }
            if (key.name === "pageup") {
                scrollOffset = Math.max(0, scrollOffset - Math.floor(overlayH * 0.7 * 0.5));
                return true;
            }
            if (key.name === "pagedown") {
                scrollOffset += Math.floor(overlayH * 0.7 * 0.5);
                return true;
            }
            // Any other key disarms stop
            stopArmed = false;
            return false;
        },
    });
}
```

